from fastapi import FastAPI, HTTPException
from pydantic import BaseModel, Field
from web3 import Web3
from eth_account.messages import encode_defunct
import re

app = FastAPI(title="Ethereum Signature Auth Service")


class VerifyRequest(BaseModel):
    message: str = Field(..., min_length=1)
    signature: str = Field(..., min_length=1)
    expected_address: str | None = None


class VerifyResponse(BaseModel):
    authenticated: bool
    address: str
    matches_expected: bool | None = None


def normalize_address(address: str) -> str:
    if not isinstance(address, str):
        raise ValueError("Invalid address")
    if not Web3.is_address(address):
        raise ValueError("Invalid Ethereum address")
    return Web3.to_checksum_address(address)


def normalize_signature(signature: str) -> str:
    if not isinstance(signature, str):
        raise ValueError("Invalid signature")
    signature = signature.strip()
    if not re.fullmatch(r"0x[a-fA-F0-9]{130}", signature):
        raise ValueError("Invalid signature format")
    return signature


def recover_signer(message: str, signature: str) -> str:
    message_encoded = encode_defunct(text=message)
    recovered = Web3().eth.account.recover_message(message_encoded, signature=signature)
    if not Web3.is_address(recovered):
        raise ValueError("Failed to recover address")
    return Web3.to_checksum_address(recovered)


@app.get("/health")
def health():
    return {"status": "ok"}


@app.post("/auth/verify", response_model=VerifyResponse)
def verify_signature(req: VerifyRequest):
    try:
        signature = normalize_signature(req.signature)
        recovered_address = recover_signer(req.message, signature)
        matches_expected = None

        if req.expected_address is not None:
            expected = normalize_address(req.expected_address)
            matches_expected = recovered_address.lower() == expected.lower()
            if not matches_expected:
                raise HTTPException(status_code=401, detail="Signature does not match expected address")

        return VerifyResponse(
            authenticated=True,
            address=recovered_address,
            matches_expected=matches_expected,
        )
    except ValueError as e:
        raise HTTPException(status_code=400, detail=str(e))
    except HTTPException:
        raise
    except Exception:
        raise HTTPException(status_code=401, detail="Invalid signature")


